// Filter out WhatsApp status webhooks (delivered, read, sent)
// Only process actual message webhooks

const items = $input.all();
const processedItems = [];

for (const item of items) {
  const body = item.json.body;

  // Check if this is a message webhook (not a status webhook)
  const hasMessages = body?.entry?.[0]?.changes?.[0]?.value?.messages;

  if (!hasMessages) {
    // This is a status webhook (delivered, read, sent) - skip it
    continue;
  }

  // Extract message data
  const messageText = body?.entry?.[0]?.changes?.[0]?.value?.messages?.[0]?.text?.body || body?.message_text || '';
  const messageType = body?.entry?.[0]?.changes?.[0]?.value?.messages?.[0]?.type || body?.message_type || 'text';
  const from = body?.entry?.[0]?.changes?.[0]?.value?.messages?.[0]?.from || body?.from || '';

  processedItems.push({
    json: {
      message_text: messageText,
      message_type: messageType,
      from: from
    }
  });
}

return processedItems;

