// Obter dados de entrada
const cpf = $('Merge State').item.json.message_text;
const html = $('Consulta e-SAJ').item.json.data || '';

console.log('Processando CPF:', cpf);
console.log('HTML recebido:', html.length, 'caracteres');

// Obter data e hora atual
const agora = new Date();
const dataHora = agora.toLocaleString('pt-BR', {
  timeZone: 'America/Sao_Paulo',
  day: '2-digit',
  month: '2-digit',
  year: 'numeric',
  hour: '2-digit',
  minute: '2-digit'
});

// >>> NOVO: Funcoes de filtro (Janeiro 2026)
// Verifica se eh Requerente (nao Sucessor/Herdeiro)
function isRequerente(textoBloco) {
  const hasReqte = /Reqte|Favorecido/i.test(textoBloco) || /tipoDeParticipacao[^>]*>\s*(Reqte|Favorecido)/i.test(textoBloco);
  const hasSucessor = /Sucessor|Herdeiro/i.test(textoBloco);
  return hasReqte && !hasSucessor;
}

// Verifica se eh Precatorio (nao RPV)
function isPrecatorio(textoBloco) {
  const classeMatch = textoBloco.match(/classeProcesso[^>]*>([^<]+)</i);
  if (classeMatch) {
    const classe = classeMatch[1].trim();
    if (classe.includes('Requisição de Pequeno Valor') || classe.includes('Requisicao de Pequeno Valor') || classe === 'RPV') {
      return false;
    }
    return classe.includes('Precatório') || classe.includes('Precatorio');
  }
  if (textoBloco.includes('Requisição de Pequeno Valor') || textoBloco.includes('Requisicao de Pequeno Valor')) {
    return false;
  }
  return textoBloco.includes('Precatório') || textoBloco.includes('Precatorio');
}

// >>> NOVO: Mascara os 5 primeiros digitos do numero do processo (Fevereiro 2026)
function mascararNumeroProcesso(numeroCompleto) {
  // Formato: 0137880-57.2021.8.26.0500
  // Resultado: XXXXX80-57.2021.8.26.0500
  if (!numeroCompleto || numeroCompleto.length < 7) return numeroCompleto;
  return 'XXXXX' + numeroCompleto.substring(5);
}
// <<< FIM NOVO

// CASO 1: Verificar se eh pagina de LISTA de processos
const hasProcessList = html.includes('Processos encontrados') || html.includes('linkProcesso');

// CASO 2: Verificar se eh pagina de DETALHE de processo unico
const isSingleProcessPage = html.includes('Tramitacao prioritaria') ||
                            (html.includes('Classe') && html.includes('Assunto') && html.includes('Foro') && html.includes('Vara'));

if (!hasProcessList && !isSingleProcessPage) {
  console.log('Nenhum processo encontrado');
  return [{
    json: {
      responseText: 'Consulta sistema do Tribunal de Justiça de SP - CPF: ' + cpf + ' - Nenhum processo encontrado, digite menu para voltar ao início',
      nome_extraido: 'N/A',
      processos_array: [],
      total_processos: 0
    }
  }];
}

console.log('Processos encontrados, extraindo dados...');

const processos = [];
let nome = 'N/A';
let processosExcluidos = 0;
let motivosExclusao = [];

// Funcao para limpar nome extraido
function limparNome(text) {
  if (!text) return 'N/A';
  return text
    .replace(/<[^>]+>/g, '')
    .replace(/\s+/g, ' ')
    .trim();
}

// Funcao para extrair apenas o nome (primeira linha antes do advogado)
function extrairApenasNome(text) {
  if (!text) return 'N/A';
  // Remove tags, pega somente o texto antes do primeiro <br> ou "Advogado"
  const semTags = text.replace(/<br\s*\/?>/gi, '\n').replace(/<[^>]+>/g, '');
  const linhas = semTags.split('\n').map(l => l.replace(/&​nbsp;/g, ' ').trim()).filter(l => l.length > 0);
  // Primeira linha nao vazia = nome do requerente
  return linhas.length > 0 ? linhas[0] : 'N/A';
}

if (isSingleProcessPage && !hasProcessList) {
  // CASO 2: Pagina de detalhe de processo unico — logica simplificada
  console.log('Processando detalhe de processo unico...');

  // 1. Numero do processo
  const numeroRegex = /\b(\d{7}-\d{2}\.\d{4}\.\d\.\d{2}\.\d{4})\b/;
  const numeroMatch = html.match(numeroRegex);
  const numeroProcesso = numeroMatch ? numeroMatch[1] : '';

  // 2. Classe: extrair do campo estruturado do cabecalho
  let classeProcesso = '';
  const classeMatch = html.match(/unj-label[^>]*>\s*Classe\s*<\/[\w]+>\s*<[\w][^>]*>\s*([^<]+)/i);
  if (classeMatch) {
    classeProcesso = classeMatch[1].trim();
  } else if (html.match(/<span[^>]*>\s*Precatório\s*<\/span>/i) || html.match(/>\s*Precatório\s*</)) {
    classeProcesso = 'Precatório';
  }
  console.log('Classe detectada:', classeProcesso);

  // 3. Se nao for Precatorio, descartar
  const ehPrecatorio = classeProcesso.toLowerCase().includes('precat');
  if (!ehPrecatorio) {
    console.log('Processo EXCLUIDO no detalhe - nao eh Precatorio, classe:', classeProcesso);
    processosExcluidos++;
    motivosExclusao.push('RPV');
  } else {
    // 4. Nome do Requerente — apenas o nome, sem advogado
    const tdNomeMatch = html.match(/class="nomeParteEAdvogado"[^>]*>([\s\S]*?)<\/td>/i);
    if (tdNomeMatch && tdNomeMatch[1]) {
      const textoNome = extrairApenasNome(tdNomeMatch[1]);
      if (textoNome !== 'N/A') {
        nome = textoNome;
        console.log('Nome encontrado (estrategia 1 - nomeParteEAdvogado):', nome);
      }
    }

    if (nome === 'N/A') {
      const reqteMatch = html.match(/Reqte[\s\S]*?<\/td>[\s\S]*?<td[^>]*>([\s\S]*?)<\/td>/i);
      if (reqteMatch && reqteMatch[1]) {
        const textoReqte = extrairApenasNome(reqteMatch[1]);
        if (textoReqte !== 'N/A') {
          nome = textoReqte;
          console.log('Nome encontrado (estrategia 2 - Reqte):', nome);
        }
      }
    }

    if (nome === 'N/A') {
      const nomeRegex2 = /Reqte[^A-Za-z]*([A-Z][a-zA-Z\u00C0-\u00FF]+(?:\s+[A-Z][a-zA-Z\u00C0-\u00FF]+)+)/;
      const nomeMatch2 = html.match(nomeRegex2);
      if (nomeMatch2 && nomeMatch2[1]) {
        const textoNome = limparNome(nomeMatch2[1]);
        if (textoNome !== 'N/A') {
          nome = textoNome;
          console.log('Nome encontrado (estrategia 3 - regex nome):', nome);
        }
      }
    }

    // 5. Ultima data de movimentacao (ultima da lista = mais antiga visivel)
    const datasMovimentacao = [...html.matchAll(/(\d{2}\/\d{2}\/\d{4})/g)].map(m => m[1]);
    const dataProcesso = datasMovimentacao.length > 0
      ? datasMovimentacao[datasMovimentacao.length - 1]
      : dataHora.split(',')[0];
    console.log('Datas de movimentacao encontradas:', datasMovimentacao);
    console.log('Data selecionada (ultima):', dataProcesso);

    if (numeroProcesso) {
      processos.push({
        numero: numeroProcesso,
        classe: classeProcesso,
        data: dataProcesso
      });
      console.log('Processo incluido:', numeroProcesso, '-', classeProcesso, '-', dataProcesso);
    }
  }

} else {
  // CASO 1: Lista de processos
  console.log('Processando lista de processos...');

  const nomeRegex = /<div class="unj-base-alt nomeParte">\s*([^<]+)/;
  const nomeMatches = html.match(nomeRegex);
  if (nomeMatches && nomeMatches[1]) {
    nome = limparNome(nomeMatches[1]);
    console.log('Nome encontrado:', nome);
  }

  const processosRegex = /<li>\s*<div id="divProcesso[^"]*"[^>]*>.*?<\/div>\s*<\/li>/gs;
  const processosMatches = html.match(processosRegex);

  if (processosMatches) {
    processosMatches.forEach((processoHtml) => {
      const numRegex = /class="linkProcesso"[^>]*>\s*([^<\s]+)/;
      const numeroMatch = processoHtml.match(numRegex);
      const numeroProcesso = numeroMatch ? numeroMatch[1].trim() : '';

      const clsRegex = /<div class="classeProcesso">([^<]+)<\/div>/;
      const classeMatch = processoHtml.match(clsRegex);
      const classeProcesso = classeMatch ? classeMatch[1].trim() : '';

      const dtRegex = /<div class="dataLocalDistribuicaoProcesso">([^<]+?)\s*-/;
      const dataMatch = processoHtml.match(dtRegex);
      const dataProcesso = dataMatch ? dataMatch[1].trim() : '';

      const ehRequerente = isRequerente(processoHtml);
      const ehPrecatorio = isPrecatorio(processoHtml);

      if (!ehRequerente) {
        console.log('Processo', numeroProcesso, '- EXCLUIDO (Sucessor/Herdeiro)');
        processosExcluidos++;
        if (!motivosExclusao.includes('Sucessor/Herdeiro')) motivosExclusao.push('Sucessor/Herdeiro');
      } else if (!ehPrecatorio) {
        console.log('Processo', numeroProcesso, '- EXCLUIDO (RPV)');
        processosExcluidos++;
        if (!motivosExclusao.includes('RPV')) motivosExclusao.push('RPV');
      } else if (numeroProcesso && classeProcesso && dataProcesso) {
        processos.push({
          numero: numeroProcesso,
          classe: classeProcesso,
          data: dataProcesso
        });
        console.log('Processo incluido:', numeroProcesso, '-', classeProcesso);
      }
    });
  }
}

console.log('Total de processos (apos filtros):', processos.length);
console.log('Processos excluidos:', processosExcluidos);
console.log('Nome final:', nome);

let response = '';

if (processos.length === 0) {
  if (processosExcluidos > 0) {
    response = 'Consulta no sistema do Tribunal de Justiça do Estado de São Paulo\n\nCPF: ' + cpf + '\n\n';
    response += 'Não foram encontrados precatórios onde você figura como requerente.\n\n';
    if (motivosExclusao.includes('RPV') && motivosExclusao.includes('Sucessor/Herdeiro')) {
      response += 'Os processos encontrados sao RPVs ou você consta como sucessor/herdeiro.';
    } else if (motivosExclusao.includes('RPV')) {
      response += 'Os processos encontrados sao Requisições de Pequeno Valor (RPV), não precatórios.';
    } else if (motivosExclusao.includes('Sucessor/Herdeiro')) {
      response += 'Nos processos encontrados, voce consta como sucessor/herdeiro, nao como requerente titular.';
    }
    response += '\n\nDigite menu para voltar ao início.';
  } else {
    response = 'Consulta no sistema do Tribunal de Justiça do Estado de São Paulo CPF: ' + cpf + ' - Nenhum processo encontrado, digite menu para voltar ao início';
  }
} else {
  response = 'Consulta no sistema do Tribunal de Justiça do Estado de São Paulo\n\nPrezado(a) ' + nome + ', CPF: ' + cpf + ', localizamos os seguintes precatórios:\n';
  for (const processo of processos) {
    const numeroMascarado = mascararNumeroProcesso(processo.numero);
    response += '- ' + processo.data + ' ' + numeroMascarado + ' ' + processo.classe + '\n';
  }
  response += '\nConsulta oficial realizada no sistema do Tribunal de Justiça às ' + dataHora;
  response += '\n\n🔍 Podemos enviar um diagnóstico completo do seu precatório com valores atualizados, previsão de pagamento e outras informações. Valor de ~R$ 249,90~ por R$ 99,90 (promoção por tempo limitado).\n\nTem interesse em prosseguir?';
}

return [{
  json: {
    responseText: response,
    nome_extraido: nome,
    processos_array: processos,
    total_processos: processos.length
  }
}];

// Generate 6-digit verification code
const code = Math.floor(100000 + Math.random() * 900000).toString();
const email = $('Merge State').item.json.message_text;
const from = $('Merge State').item.json.from;

console.log('Codigo gerado:', code);
console.log('Email:', email);

return [{
  json: {
    verification_code: code,
    email: email,
    from: from,
    code_generated_at: new Date().toISOString()
  }
}];

// Validate verification code
const inputCode = $('Merge State').item.json.message_text;
const storedCode = $('Merge State').item.json.stored_code;
const storedEmail = $('Merge State').item.json.stored_email;
const minutesSinceUpdate = $('Merge State').item.json.minutes_since_update || 0;
const from = $('Merge State').item.json.from;

console.log('Codigo digitado:', inputCode);
console.log('Codigo armazenado:', storedCode);
console.log('Minutos desde update:', minutesSinceUpdate);

// Check if code expired (15 minutes)
const isExpired = minutesSinceUpdate > 15;

// Check if code matches
const isValid = inputCode === storedCode && !isExpired;

let response = '';
let newState = 'AWAITING_CODE';
let triggerPayment = false;

if (isExpired) {
  response = '⏰ *Código expirou!*\n\nO código de verificação expirou. Por favor, digite seu email novamente para receber um novo código.';
  newState = 'AWAITING_EMAIL';
} else if (isValid) {
  response = '✅ *Email verificado com sucesso!*\n\n💳 Estamos gerando seu link de pagamento...\n\n⏳ Aguarde alguns segundos, você receberá o link aqui no WhatsApp.';
  newState = 'AWAITING_PAYMENT';
  triggerPayment = true;
} else {
  response = '❌ *Código incorreto!*\n\nO código digitado não confere. Por favor, verifique e digite novamente o código de 6 dígitos enviado para seu email.';
  newState = 'AWAITING_CODE';
}

return [{
  json: {
    route: 'CODE',
    response: response,
    new_state: newState,
    code_valid: isValid,
    code_expired: isExpired,
    stored_email: storedEmail,
    trigger_payment: triggerPayment,
    from: from
  }
}];

const responseNodes = [
  'Response MENU', 'Response AGENT', 'Response CONSULTAR',
  'Response CPF', 'Response EMAIL', 'Response CODE',
  'Response CONFIRM_YES', 'Response CONFIRM_NO',
  'Response NOT_TEXT', 'Response INFO_PRECATORIOS'
];

let response = '';

// Tenta nós Response primeiro
for (const nodeName of responseNodes) {
  try {
    const r = $(nodeName).item.json.response;
    if (r) { response = r; break; }
  } catch(e) { continue; }
}

// Tenta Validate Code diretamente
if (!response) {
  try {
    const r = $('Validate Code').item.json.response;
    if (r) response = r;
  } catch(e) {}
}

// Tenta input direto (vem do Update State que preserva response)
if (!response) {
  try {
    const r = $input.first().json.response;
    if (r) response = r;
  } catch(e) {}
}

// Fallback timeout
if (!response) {
  try { response = $('Merge State').item.json.timeout_message || ''; } catch(e) {}
}

if (!response) response = 'Olá! Digite menu para começar.';

const from = $('Merge State').item.json.from || '';
const new_state = $input.first().json.new_state || 'IDLE';

return [{ json: { response, from, new_state } }];

